      fun ?response ->
        fun ?requestMessageId ->
          fun ?conversationState ->
            fun ?nextMessageToken ->
              fun ?conversationSessionData ->
                fun ?chunkedResponseTerminated ->
                  fun () ->
                    {
                      type_;
                      response;
                      requestMessageId;
                      conversationState;
                      nextMessageToken;
                      conversationSessionData;
                      chunkedResponseTerminated
                    }
    let error_of_json name json =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_json json)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_json json)
      | "UnprocessableContentException" ->
          `UnprocessableContentException
            (UnprocessableContentException.of_json json)
      | "ValidationException" ->
          `ValidationException (ValidationException.of_json json)
      | name ->
          `Unknown_operation_error
            (name, (Some (Yojson.Safe.to_string json)))
    let error_of_xml name xml =
      match name with
      | "AccessDeniedException" ->
          `AccessDeniedException (AccessDeniedException.of_xml xml)
      | "ResourceNotFoundException" ->
          `ResourceNotFoundException (ResourceNotFoundException.of_xml xml)
      | "UnprocessableContentException" ->
          `UnprocessableContentException
            (UnprocessableContentException.of_xml xml)
      | "ValidationException" ->
          `ValidationException (ValidationException.of_xml xml)
      | name ->
          `Unknown_operation_error (name, (Some (Awso.Xml.to_string xml)))
    let error_to_json : error -> Yojson.Safe.t =
      function
      | `AccessDeniedException e ->
          `Assoc
            [("error", (`String "AccessDeniedException"));
            ("details", (AccessDeniedException.to_json e))]
      | `ResourceNotFoundException e ->
          `Assoc
            [("error", (`String "ResourceNotFoundException"));
            ("details", (ResourceNotFoundException.to_json e))]
      | `UnprocessableContentException e ->
          `Assoc
            [("error", (`String "UnprocessableContentException"));
            ("details", (UnprocessableContentException.to_json e))]
      | `ValidationException e ->
          `Assoc
            [("error", (`String "ValidationException"));
            ("details", (ValidationException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value x =
      structure_to_value
        [("type", (Option.map x.type_ ~f:MessageType.to_value));
        ("response", (Option.map x.response ~f:MessageOutput.to_value));
        ("requestMessageId",
          (Option.map x.requestMessageId ~f:Uuid.to_value));
        ("conversationState",
          (Option.map x.conversationState ~f:ConversationState.to_value));
        ("nextMessageToken",
          (Option.map x.nextMessageToken ~f:NextToken.to_value));
        ("conversationSessionData",
          (Option.map x.conversationSessionData
             ~f:RuntimeSessionDataList.to_value));
        ("chunkedResponseTerminated",
          (Option.map x.chunkedResponseTerminated ~f:Boolean.to_value))]
    let to_query v = to_query to_value v
