      let conversationSessionData =
        (Option.map ~f:RuntimeSessionDataList.of_xml)
          (Xml.child xml_arg0 "conversationSessionData") in
      let nextMessageToken =
        (Option.map ~f:NextToken.of_xml)
          (Xml.child xml_arg0 "nextMessageToken") in
      let conversationState =
        (Option.map ~f:ConversationState.of_xml)
          (Xml.child xml_arg0 "conversationState") in
      let requestMessageId =
