      let response =
        (Option.map ~f:MessageOutput.of_xml) (Xml.child xml_arg0 "response") in
      let type_ =
        (Option.map ~f:MessageType.of_xml) (Xml.child xml_arg0 "type") in
      make ?chunkedResponseTerminated ?conversationSessionData
        ?nextMessageToken ?conversationState ?requestMessageId ?response
        ?type_ ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
