      let nextMessageToken =
        field_map json__ "nextMessageToken" NextToken.of_json in
      let conversationState =
        field_map json__ "conversationState" ConversationState.of_json in
      let requestMessageId = field_map json__ "requestMessageId" Uuid.of_json in
      let response = field_map json__ "response" MessageOutput.of_json in
      let type_ = field_map json__ "type" MessageType.of_json in
      make ?chunkedResponseTerminated ?conversationSessionData
        ?nextMessageToken ?conversationState ?requestMessageId ?response
